1	/**
2	 * OpenAIAdapter — direct OpenAI API integration via the official `openai` SDK.
3	 *
4	 * Architecture (DECISIONS.md D6, docs/oracle/02 §"Shared architecture"):
5	 * - Calls OpenAI's REST API directly using the official SDK.
6	 * - NO Vercel AI SDK and NO OpenRouter in this path.
7	 * - Authenticates via `OPENAI_API_KEY` env var.
8	 *
9	 * Caching strategy (round 1 — automatic prefix caching):
10	 * - OpenAI auto-caches prompts >= 1024 tokens on the same stable prefix; no
11	 *   client action required. Cache hits show up in
12	 *   `usage.prompt_tokens_details.cached_tokens` and are normalized into
13	 *   `OracleUsage.cachedInputTokens`.
14	 * - Explicit cache-retention extensions (`prompt_cache_key`,
15	 *   `prompt_cache_retention`) are a round-2 follow-up.
16	 *
17	 * Structured output:
18	 * - Uses `response_format: { type: 'json_schema', json_schema: { name,
19	 *   strict: true, schema } }`. Strict mode enforces the JSON Schema 100%
20	 *   on the model — refusals come back as a `refusal` field on the message.
21	 *
22	 * Per docs/oracle/02-provider-native-ai-architecture.md → "OpenAI direct".
23	 */
24	
25	import OpenAI, { toFile } from 'openai';
26	import type { ChatCompletion, ChatCompletionMessageParam } from 'openai/resources/chat/completions';
27	import type {
28	  OracleObjectResult,
29	  OracleTextResult,
30	  OracleUsage,
31	} from '../client/types';
32	import type { OracleModelRoute, ReasoningEffort } from '../routes';
33	import type {
34	  BatchResultItem,
35	  BatchStatus,
36	  GenerateObjectArgs,
37	  GenerateTextArgs,
38	  OracleProviderAdapter,
39	  RetrieveBatchArgs,
40	  RetrieveBatchResult,
41	  SubmitBatchArgs,
42	  SubmitBatchResult,
43	} from './types';
44	import { pickOpenAICacheRetention, toOpenAIImageContent } from './cache-utils';
45	import { flattenPlan, parseJsonOrRaw, tryZodParse, zodToJsonSchema } from './vertex-gemini-adapter';
46	
47	export interface OpenAIAdapterOptions {
48	  /** API key. Defaults to env OPENAI_API_KEY. */
49	  apiKey?: string;
50	  /** OpenAI organization. Defaults to env OPENAI_ORG_ID. */
51	  organization?: string;
52	}
53	
54	export class OpenAIAdapter implements OracleProviderAdapter {
55	  readonly provider = 'openai' as const;
56	  private readonly client: OpenAI;
57	
58	  constructor(opts: OpenAIAdapterOptions = {}) {
59	    const apiKey = opts.apiKey ?? process.env.OPENAI_API_KEY;
60	    if (!apiKey) {
61	      throw new Error(
62	        'OpenAIAdapter: OPENAI_API_KEY is not set. ' +
63	          'Set it in .env.local or pass {apiKey} explicitly.',
64	      );
65	    }
66	    this.client = new OpenAI({
67	      apiKey,
68	      organization: opts.organization ?? process.env.OPENAI_ORG_ID,
69	    });
70	  }
71	
72	  async generateText(args: GenerateTextArgs): Promise<OracleTextResult> {
73	    const { plan, route, providerOptions } = args;
74	    const { systemPrompt, userMessage } = flattenPlan(plan);
75	    const messages = this.buildMessages(systemPrompt, userMessage, providerOptions);
76	    const callStartedAt = Date.now();
77	    const reasoningEffort = openaiEffort(route.reasoningEffort);
78	    const promptCacheRetention = pickOpenAICacheRetention(plan.taskType, providerOptions);
79	    const completion = await this.client.chat.completions.create({
80	      model: route.modelId,
81	      messages,
82	      prompt_cache_retention: promptCacheRetention,
83	      temperature:
84	        typeof providerOptions?.temperature === 'number'
85	          ? providerOptions.temperature
86	          : undefined,
87	      // Modern OpenAI models use max_completion_tokens (o-series rejects max_tokens).
88	      ...(typeof providerOptions?.maxOutputTokens === 'number'
89	        ? { max_completion_tokens: providerOptions.maxOutputTokens }
90	        : {}),
91	      ...(reasoningEffort ? { reasoning_effort: reasoningEffort } : {}),
92	    });
93	    const latencyMs = Date.now() - callStartedAt;
94	    const choice = completion.choices[0];
95	    return {
96	      text: choice?.message?.content ?? '',
97	      usage: this.normalizeUsage(completion, latencyMs),
98	      rawResponse: completion,
99	    };
100	  }
101	
102	  async generateObject<TSchema, TOutput>(
103	    args: GenerateObjectArgs<TSchema>,
104	  ): Promise<OracleObjectResult<TOutput>> {
105	    const { plan, route, schema, providerOptions } = args;
106	    const { systemPrompt, userMessage } = flattenPlan(plan);
107	    // OpenAI strict mode requires every property to be required +
108	    // additionalProperties: false. The Zod JSON-schema converter produces
109	    // this shape for closed objects; we layer one safety net on top.
110	    const jsonSchema = stripIncompatibleFields(
111	      zodToJsonSchema(schema) as Record<string, unknown>,
112	    );
113	    const callStartedAt = Date.now();
114	    const reasoningEffort = openaiEffort(route.reasoningEffort);
115	    const promptCacheRetention = pickOpenAICacheRetention(plan.taskType, providerOptions);
116	    const completion = await this.client.chat.completions.create({
117	      model: route.modelId,
118	      messages: this.buildMessages(systemPrompt, userMessage, providerOptions),
119	      prompt_cache_retention: promptCacheRetention,
120	      temperature:
121	        typeof providerOptions?.temperature === 'number'
122	          ? providerOptions.temperature
123	          : 0.1,
124	      response_format: {
125	        type: 'json_schema',
126	        json_schema: {
127	          name: 'oracle_structured_output',
128	          strict: true,
129	          schema: jsonSchema,
130	        },
131	      },
132	      ...(reasoningEffort ? { reasoning_effort: reasoningEffort } : {}),
133	    });
134	    const latencyMs = Date.now() - callStartedAt;
135	    const choice = completion.choices[0];
136	    const refusal = choice?.message?.refusal;
137	    if (refusal) {
138	      throw new Error(`OpenAIAdapter.generateObject: model refused: ${refusal}`);
139	    }
140	    const raw = choice?.message?.content;
141	    if (!raw) {
142	      throw new Error(
143	        `OpenAIAdapter.generateObject: empty response. finish_reason=${choice?.finish_reason}`,
144	      );
145	    }
146	    const parsed = parseJsonOrRaw(raw);
147	    const validated = tryZodParse<TOutput>(schema, parsed);
148	    return {
149	      object: (validated ?? parsed) as TOutput,
150	      usage: this.normalizeUsage(completion, latencyMs),
151	      rawResponse: completion,
152	    };
153	  }
154	
155	  /**
156	   * Submit a batch of requests to OpenAI's Batch API. Builds a JSONL file
157	   * (one request per line, each with a caller-supplied `custom_id`),
158	   * uploads it via `client.files.create`, then opens the batch via
159	   * `client.batches.create` against `/v1/chat/completions`. 50% off sync
160	   * pricing with a 24-hour SLA.
161	   *
162	   * Returns the batch ID + the input file ID (so retrieveBatch can clean it
163	   * up after results are pulled, if desired).
164	   */
165	  async submitBatch(args: SubmitBatchArgs): Promise<SubmitBatchResult> {
166	    const { route, requests, jsonSchema } = args;
167	    const reasoningEffort = openaiEffort(route.reasoningEffort);
168	    const sharedResponseFormat = jsonSchema
169	      ? {
170	          type: 'json_schema' as const,
171	          json_schema: {
172	            name: 'oracle_structured_output',
173	            strict: true,
174	            schema: stripIncompatibleFields(jsonSchema as Record<string, unknown>),
175	          },
176	        }
177	      : undefined;
178	
179	    const lines: string[] = [];
180	    for (const req of requests) {
181	      const { systemPrompt, userMessage } = flattenPlan(req.plan);
182	      const body: Record<string, unknown> = {
183	        model: route.modelId,
184	        messages: this.buildMessages(systemPrompt, userMessage),
185	        temperature: jsonSchema ? 0.1 : undefined,
186	      };
187	      if (sharedResponseFormat) body.response_format = sharedResponseFormat;
188	      if (reasoningEffort) body.reasoning_effort = reasoningEffort;
189	      // Strip undefined to keep the JSONL clean.
190	      for (const k of Object.keys(body)) if (body[k] === undefined) delete body[k];
191	
192	      lines.push(JSON.stringify({
193	        custom_id: req.customId,
194	        method: 'POST',
195	        url: '/v1/chat/completions',
196	        body,
197	      }));
198	    }
199	    const jsonl = lines.join('\n') + '\n';
200	
201	    const uploaded = await this.client.files.create({
202	      file: await toFile(Buffer.from(jsonl, 'utf-8'), 'oracle-batch-input.jsonl'),
203	      purpose: 'batch',
204	    });
205	
206	    const batch = await this.client.batches.create({
207	      input_file_id: uploaded.id,
208	      endpoint: '/v1/chat/completions',
209	      completion_window: '24h',
210	    });
211	
212	    return {
213	      providerBatchId: batch.id,
214	      providerMetadata: { inputFileId: uploaded.id },
215	    };
216	  }
217	
218	  /**
219	   * Poll status and, when complete, download and parse the output JSONL.
220	   * Each output line carries the caller's `custom_id` so results map back
221	   * to the originating BatchRequest.
222	   */
223	  async retrieveBatch(args: RetrieveBatchArgs): Promise<RetrieveBatchResult> {
224	    const { providerBatchId } = args;
225	    const batch = await this.client.batches.retrieve(providerBatchId);
226	    const status = mapOpenAIBatchStatus(batch.status);
227	    const counts = batch.request_counts;
228	
229	    if (status === 'in_progress' || status === 'submitted') {
230	      return {
231	        status,
232	        requestCount: counts?.total,
233	        completedCount: counts?.completed,
234	        failedCount: counts?.failed,
235	      };
236	    }
237	
238	    if (status !== 'completed') {
239	      // failed / expired / canceled — surface the first error if available
240	      const errMsg = batch.errors?.data?.[0]?.message;
241	      return {
242	        status,
243	        error: errMsg,
244	        requestCount: counts?.total,
245	        completedCount: counts?.completed,
246	        failedCount: counts?.failed,
247	      };
248	    }
249	
250	    if (!batch.output_file_id) {
251	      return {
252	        status: 'failed',
253	        error: 'completed batch has no output_file_id',
254	      };
255	    }
256	
257	    const fileResponse = await this.client.files.content(batch.output_file_id);
258	    const outputText = await fileResponse.text();
259	    const results: BatchResultItem[] = [];
260	
261	    for (const rawLine of outputText.split('\n')) {
262	      if (!rawLine.trim()) continue;
263	      let parsed: {
264	        custom_id: string;
265	        response: { status_code: number; body: ChatCompletion } | null;
266	        error: { code?: string; message?: string } | null;
267	      };
268	      try {
269	        parsed = JSON.parse(rawLine);
270	      } catch {
271	        // Malformed line — the customId is unrecoverable. Downstream marks the
272	        // missing request failed, but don't drop it silently: log the bad line
273	        // (truncated) so a corrupted batch output is visible, not invisible.
274	        console.error(
275	          `[OpenAIAdapter] unparseable batch result line (request result LOST): ${rawLine.slice(0, 200)}`,
276	        );
277	        continue;
278	      }
279	
280	      if (parsed.error || !parsed.response) {
281	        results.push({
282	          customId: parsed.custom_id,
283	          success: false,
284	          error: parsed.error?.message ?? `status ${parsed.response?.status_code ?? 'unknown'}`,
285	        });
286	        continue;
287	      }
288	
289	      const completion = parsed.response.body;
290	      const choice = completion.choices?.[0];
291	      const refusal = choice?.message?.refusal;
292	      if (refusal) {
293	        results.push({
294	          customId: parsed.custom_id,
295	          success: false,
296	          error: `model refused: ${refusal}`,
297	          usage: this.normalizeUsage(completion, 0),
298	        });
299	        continue;
300	      }
301	
302	      const rawContent = choice?.message?.content ?? '';
303	      // Try JSON parse first (structured output); fall back to plain text.
304	      let output: unknown;
305	      let text: string | undefined;
306	      try {
307	        output = JSON.parse(rawContent);
308	      } catch {
309	        text = rawContent;
310	      }
311	
312	      results.push({
313	        customId: parsed.custom_id,
314	        success: true,
315	        output,
316	        text,
317	        usage: this.normalizeUsage(completion, 0),
318	      });
319	    }
320	
321	    return {
322	      status: 'completed',
323	      results,
324	      requestCount: counts?.total,
325	      completedCount: counts?.completed,
326	      failedCount: counts?.failed,
327	    };
328	  }
329	
330	  private buildMessages(
331	    systemPrompt: string,
332	    userMessage: string,
333	    providerOptions?: Record<string, unknown>,
334	  ): ChatCompletionMessageParam[] {
335	    const override = providerOptions?.messages as
336	      | ChatCompletionMessageParam[]
337	      | undefined;
338	    if (Array.isArray(override) && override.length > 0) {
339	      // Translate provider-neutral image parts → OpenAI `image_url` at dispatch.
340	      const translated = override.map(
341	        (m) => ({ ...m, content: toOpenAIImageContent(m.content) }) as ChatCompletionMessageParam,
342	      );
343	      if (systemPrompt && !translated.some((m) => m.role === 'system')) {
344	        return [{ role: 'system', content: systemPrompt }, ...translated];
345	      }
346	      return translated;
347	    }
348	    const msgs: ChatCompletionMessageParam[] = [];
349	    if (systemPrompt) msgs.push({ role: 'system', content: systemPrompt });
350	    msgs.push({ role: 'user', content: userMessage });
351	    return msgs;
352	  }
353	
354	  /**
355	   * Normalize OpenAI usage. OpenAI exposes auto-prefix-cache reads under
356	   * `usage.prompt_tokens_details.cached_tokens`, and reasoning tokens (o-series)
357	   * under `usage.completion_tokens_details.reasoning_tokens`.
358	   */
359	  private normalizeUsage(
360	    completion: ChatCompletion,
361	    latencyMs: number,
362	  ): OracleUsage {
363	    const u = completion.usage;
364	    return {
365	      inputTokens: u?.prompt_tokens,
366	      outputTokens: u?.completion_tokens,
367	      cachedInputTokens: u?.prompt_tokens_details?.cached_tokens,
368	      reasoningTokens: u?.completion_tokens_details?.reasoning_tokens,
369	      latencyMs,
370	      providerRequestId: completion.id,
371	      rawUsageJson: u,
372	    };
373	  }
374	}
375	
376	/**
377	 * OpenAI's strict JSON-schema mode is pickier than the JSON Schema that Zod's
378	 * converter emits. `walk` reconciles two gaps:
379	 *   1. It rejects keywords the OpenAPI subset doesn't support — most commonly
380	 *      `$schema` and `default` on optional properties — so we strip those.
381	 *   2. It requires EVERY key in an object's `properties` to also appear in
382	 *      `required`. Zod omits `.optional()` props from `required`, which makes
383	 *      strict mode 400 ("Invalid schema ... Missing 'sensitivityReason'") and
384	 *      hard-breaks every OpenAI extraction call. We force every property
385	 *      required; optional fields are simply always emitted by the model.
386	 */
387	function stripIncompatibleFields(
388	  schema: Record<string, unknown>,
389	): Record<string, unknown> {
390	  const cloned = JSON.parse(JSON.stringify(schema)) as Record<string, unknown>;
391	  walk(cloned);
392	  return cloned;
393	}
394	
395	/**
396	 * Translate unified ReasoningEffort to OpenAI's `reasoning_effort` enum.
397	 * Only meaningful for the o-series (o1/o3/o4) and GPT-5 reasoning models —
398	 * non-reasoning models silently accept and ignore the param.
399	 *
400	 * 'off' returns undefined so the caller can omit the param entirely.
401	 */
402	function openaiEffort(effort: ReasoningEffort | undefined): 'low' | 'medium' | 'high' | undefined {
403	  if (!effort || effort === 'off') return undefined;
404	  return effort; // 'low' | 'medium' | 'high' pass through unchanged
405	}
406	
407	function walk(node: unknown): void {
408	  if (node === null || typeof node !== 'object') return;
409	  if (Array.isArray(node)) {
410	    for (const item of node) walk(item);
411	    return;
412	  }
413	  const obj = node as Record<string, unknown>;
414	  delete obj.$schema;
415	  delete obj.default;
416	  // Strict mode requires `required` to cover every property. Recompute it for
417	  // any object node that declares `properties` (Zod only lists non-optional
418	  // keys, which 400s strict validation).
419	  const props = obj.properties;
420	  if (props !== null && typeof props === 'object' && !Array.isArray(props)) {
421	    obj.required = Object.keys(props as Record<string, unknown>);
422	  }
423	  for (const value of Object.values(obj)) walk(value);
424	}
425	
426	/**
427	 * Map OpenAI's batch.status enum onto our provider-agnostic BatchStatus.
428	 *
429	 *   validating | in_progress | finalizing → 'in_progress'
430	 *   completed                              → 'completed'
431	 *   failed                                 → 'failed'
432	 *   expired                                → 'expired'
433	 *   cancelling | cancelled                 → 'canceled'
434	 */
435	function mapOpenAIBatchStatus(s: string): BatchStatus {
436	  switch (s) {
437	    case 'completed': return 'completed';
438	    case 'failed': return 'failed';
439	    case 'expired': return 'expired';
440	    case 'cancelling':
441	    case 'cancelled':
442	      return 'canceled';
443	    case 'validating':
444	    case 'in_progress':
445	    case 'finalizing':
446	      return 'in_progress';
447	    default:
448	      // Unknown → treat as still-running so the drain task polls again
449	      return 'in_progress';
450	  }
451	}
