1	/**
2	 * GoogleGeminiAdapter — direct Gemini Developer API integration via `@google/genai`.
3	 *
4	 * This is intentionally separate from `VertexGeminiAdapter`. Some Gemini API
5	 * models can appear in the admin model catalog before the configured Vertex
6	 * project/region can serve them. Routes with provider `google` call the
7	 * Gemini API with an API key; routes with provider `vertex` keep using ADC,
8	 * Vertex regions, explicit caches, and Vertex Batch Prediction.
9	 */
10	
11	import { GoogleGenAI, ThinkingLevel } from '@google/genai';
12	import type { Content, GenerateContentResponse, Part } from '@google/genai';
13	import { createSign } from 'node:crypto';
14	import type { OracleObjectResult, OracleTextResult, OracleUsage } from '../client/types';
15	import type { OracleModelRoute } from '../routes';
16	import type {
17	  GenerateObjectArgs,
18	  GenerateTextArgs,
19	  OracleProviderAdapter,
20	} from './types';
21	import {
22	  flattenPlan,
23	  parseJsonOrRaw,
24	  tryZodParse,
25	  zodToJsonSchema,
26	} from './vertex-gemini-adapter';
27	
28	/**
29	 * Default per-request timeout for Gemini generateContent calls. The old value
30	 * was a hard-coded 60s, which aborted gemini-2.5-flash extraction on dense
31	 * image-derived transcripts every time (~60.1s). Vision + extraction calls can
32	 * legitimately run past 2.5 minutes, so the default is 3 minutes and it can be
33	 * overridden via GOOGLE_GEMINI_REQUEST_TIMEOUT_MS or the constructor option.
34	 */
35	const DEFAULT_GEMINI_REQUEST_TIMEOUT_MS = 180_000;
36	
37	function parseTimeoutEnv(raw: string | undefined): number | undefined {
38	  if (raw === undefined) return undefined;
39	  const parsed = Number(raw);
40	  return Number.isFinite(parsed) && parsed > 0 ? parsed : undefined;
41	}
42	
43	export interface GoogleGeminiAdapterOptions {
44	  /** Gemini API key. Defaults to GEMINI_API_KEY, then GOOGLE_API_KEY. */
45	  apiKey?: string;
46	  /**
47	   * Per-request timeout in ms for generateContent calls. Defaults to
48	   * GOOGLE_GEMINI_REQUEST_TIMEOUT_MS, then DEFAULT_GEMINI_REQUEST_TIMEOUT_MS.
49	   */
50	  requestTimeoutMs?: number;
51	}
52	
53	export class GoogleGeminiAdapter implements OracleProviderAdapter {
54	  readonly provider = 'google' as const;
55	  private readonly client: GoogleGenAI | null;
56	  private readonly serviceAccountJson: string | null;
57	  private readonly requestTimeoutMs: number;
58	
59	  constructor(opts: GoogleGeminiAdapterOptions = {}) {
60	    const apiKey = opts.apiKey ?? process.env.GEMINI_API_KEY ?? process.env.GOOGLE_API_KEY;
61	    this.serviceAccountJson = process.env.GOOGLE_APPLICATION_CREDENTIALS_JSON ?? null;
62	    if (!apiKey && !this.serviceAccountJson) {
63	      throw new Error(
64	        'GoogleGeminiAdapter: GEMINI_API_KEY or GOOGLE_APPLICATION_CREDENTIALS_JSON is not set. Set one for google/* routes.',
65	      );
66	    }
67	    this.requestTimeoutMs =
68	      opts.requestTimeoutMs ??
69	      parseTimeoutEnv(process.env.GOOGLE_GEMINI_REQUEST_TIMEOUT_MS) ??
70	      DEFAULT_GEMINI_REQUEST_TIMEOUT_MS;
71	    this.client = apiKey
72	      ? new GoogleGenAI({ apiKey, httpOptions: { timeout: this.requestTimeoutMs } })
73	      : null;
74	  }
75	
76	  async generateText(args: GenerateTextArgs): Promise<OracleTextResult> {
77	    const { plan, route, providerOptions } = args;
78	    const { systemPrompt, userMessage } = flattenPlan(plan);
79	    const callStartedAt = Date.now();
80	
81	    const contents = buildContents(userMessage, providerOptions);
82	    const generationConfig = {
83	      temperature:
84	        typeof providerOptions?.temperature === 'number'
85	          ? providerOptions.temperature
86	          : undefined,
87	      maxOutputTokens:
88	        typeof providerOptions?.maxOutputTokens === 'number'
89	          ? providerOptions.maxOutputTokens
90	          : undefined,
91	      ...geminiThinkingConfig(route),
92	    };
93	    const response = this.client
94	      ? await this.client.models.generateContent({
95	          model: route.modelId,
96	          contents,
97	          config: {
98	            systemInstruction: systemPrompt || undefined,
99	            ...generationConfig,
100	          },
101	        })
102	      : await this.generateContentWithOAuth({
103	          modelId: route.modelId,
104	          contents,
105	          systemPrompt,
106	          generationConfig,
107	        });
108	
109	    return {
110	      text: extractTextFromGeminiResponse(response),
111	      usage: normalizeGeminiUsage(response, Date.now() - callStartedAt),
112	      rawResponse: response,
113	    };
114	  }
115	
116	  async generateObject<TSchema, TOutput>(
117	    args: GenerateObjectArgs<TSchema>,
118	  ): Promise<OracleObjectResult<TOutput>> {
119	    const { plan, route, schema, providerOptions } = args;
120	    const { systemPrompt, userMessage } = flattenPlan(plan);
121	    const callStartedAt = Date.now();
122	
123	    const contents: Content[] = [{ role: 'user', parts: [{ text: userMessage }] }];
124	    const jsonSchema = zodToJsonSchema(schema);
125	    const commonConfig = {
126	      temperature: 0.1,
127	      // Output-token budget so a dense extraction doesn't truncate the JSON
128	      // (truncated JSON parses as a raw string and fails the schema).
129	      ...(typeof providerOptions?.maxOutputTokens === 'number'
130	        ? { maxOutputTokens: providerOptions.maxOutputTokens }
131	        : {}),
132	      ...geminiThinkingConfig(route),
133	    };
134	    const sdkConfig = {
135	      ...commonConfig,
136	      responseMimeType: 'application/json',
137	      responseJsonSchema: jsonSchema as unknown,
138	    };
139	    const restConfig = {
140	      ...commonConfig,
141	      responseMimeType: 'application/json',
142	      responseSchema: toGeminiRestSchema(jsonSchema),
143	    };
144	    const response = this.client
145	      ? await this.client.models.generateContent({
146	          model: route.modelId,
147	          contents,
148	          config: sdkConfig,
149	        })
150	      : await this.generateContentWithOAuth({
151	          modelId: route.modelId,
152	          contents,
153	          systemPrompt,
154	          generationConfig: restConfig,
155	        });
156	
157	    const text = extractTextFromGeminiResponse(response);
158	    const parsed = parseJsonOrRaw(text);
159	    const validated = tryZodParse<TOutput>(schema, parsed);
160	
161	    return {
162	      object: (validated ?? parsed) as TOutput,
163	      usage: normalizeGeminiUsage(response, Date.now() - callStartedAt),
164	      rawResponse: response,
165	    };
166	  }
167	
168	  private async generateContentWithOAuth(input: {
169	    modelId: string;
170	    contents: Content[];
171	    systemPrompt: string;
172	    generationConfig: Record<string, unknown>;
173	  }): Promise<GenerateContentResponse> {
174	    if (!this.serviceAccountJson) {
175	      throw new Error('GoogleGeminiAdapter: service account JSON missing for OAuth request.');
176	    }
177	    const token = await getGenerativeLanguageAccessToken(this.serviceAccountJson);
178	    const res = await fetch(
179	      `https://generativelanguage.googleapis.com/v1beta/models/${input.modelId}:generateContent`,
180	      {
181	        method: 'POST',
182	        headers: {
183	          Authorization: `Bearer ${token}`,
184	          'Content-Type': 'application/json',
185	          Accept: 'application/json',
186	        },
187	        body: JSON.stringify({
188	          contents: input.contents,
189	          systemInstruction: input.systemPrompt
190	            ? { parts: [{ text: input.systemPrompt }] }
191	            : undefined,
192	          generationConfig: stripUndefined(input.generationConfig),
193	        }),
194	        signal: AbortSignal.timeout(this.requestTimeoutMs),
195	      },
196	    );
197	    if (!res.ok) {
198	      throw new Error(`Gemini API generateContent failed: ${res.status} ${await res.text()}`);
199	    }
200	    return (await res.json()) as GenerateContentResponse;
201	  }
202	}
