204	function buildContents(
205	  userMessage: string,
206	  providerOptions?: Record<string, unknown>,
207	): Content[] {
208	  const messages = providerOptions?.messages as
209	    | Array<{ role: 'user' | 'assistant' | 'system'; content: unknown }>
210	    | undefined;
211	  if (Array.isArray(messages) && messages.length > 0) {
212	    return messages
213	      .filter((m) => m.role !== 'system')
214	      .map((m) => ({
215	        role: m.role === 'assistant' ? 'model' : 'user',
216	        parts: toGeminiParts(m.content),
217	      }));
218	  }
219	  return [{ role: 'user', parts: [{ text: userMessage }] }];
220	}
221	
222	function toGeminiParts(content: unknown): Part[] {
223	  if (typeof content === 'string') return [{ text: content }];
224	  if (!Array.isArray(content)) return [{ text: String(content ?? '') }];
225	  const parts: Part[] = [];
226	  for (const raw of content) {
227	    if (raw && typeof raw === 'object') {
228	      const part = raw as Record<string, unknown>;
229	      if (
230	        part.type === 'image' &&
231	        typeof part.data === 'string' &&
232	        typeof part.mimeType === 'string'
233	      ) {
234	        parts.push({ inlineData: { mimeType: part.mimeType, data: part.data } });
235	        continue;
236	      }
237	      if ((part.type === 'text' || part.type === undefined) && typeof part.text === 'string') {
238	        parts.push({ text: part.text });
239	        continue;
240	      }
241	    }
242	    parts.push({ text: String(raw) });
243	  }
244	  return parts;
245	}
