247	/**
248	 * Build the Gemini `thinkingConfig` for a route — but ONLY for models that
249	 * actually support thinking/reasoning controls. Attaching `thinkingLevel` to a
250	 * model that doesn't support it (e.g. gemini-2.5-flash via this adapter) makes
251	 * the API 400 with "Thinking level is not supported for this model", which
252	 * broke gemini-2.5-flash as a vision model whenever a reasoning effort was set.
253	 * `supportsReasoningControls` is the per-model capability flag (sourced from
254	 * model_capabilities.thinking), so gate on it.
255	 */
256	function geminiThinkingConfig(route: OracleModelRoute):
257	  | { thinkingConfig: { thinkingLevel: ThinkingLevel } }
258	  | Record<string, never> {
259	  if (!route.supportsReasoningControls) return {};
260	  const effort = route.reasoningEffort;
261	  if (!effort) return {};
262	  const thinkingLevel =
263	    effort === 'off' ? ThinkingLevel.MINIMAL
264	      : effort === 'low' ? ThinkingLevel.LOW
265	      : effort === 'medium' ? ThinkingLevel.MEDIUM
266	      : ThinkingLevel.HIGH;
267	  return { thinkingConfig: { thinkingLevel } };
268	}
