270	function normalizeGeminiUsage(
271	  response: GenerateContentResponse,
272	  latencyMs: number,
273	): OracleUsage {
274	  const u = response.usageMetadata ?? {};
275	  return {
276	    inputTokens: u.promptTokenCount,
277	    outputTokens: u.candidatesTokenCount,
278	    cachedInputTokens: u.cachedContentTokenCount,
279	    reasoningTokens: u.thoughtsTokenCount,
280	    latencyMs,
281	    providerRequestId: response.responseId,
282	    rawUsageJson: u,
283	  };
284	}
285	
286	function extractTextFromGeminiResponse(response: GenerateContentResponse): string {
287	  if (typeof response.text === 'string') return response.text;
288	  const candidateText = response.candidates
289	    ?.flatMap((candidate) => candidate.content?.parts ?? [])
290	    .map((part) => ('text' in part && typeof part.text === 'string' ? part.text : ''))
291	    .join('');
292	  return candidateText ?? '';
293	}
294	
295	async function getGenerativeLanguageAccessToken(saJson: string): Promise<string> {
296	  const sa = parseServiceAccountJson(saJson);
297	  const now = Math.floor(Date.now() / 1000);
298	
299	  const header = Buffer.from(JSON.stringify({ alg: 'RS256', typ: 'JWT' })).toString('base64url');
300	  const payload = Buffer.from(
301	    JSON.stringify({
302	      iss: sa.client_email,
303	      scope: 'https://www.googleapis.com/auth/generative-language',
304	      aud: 'https://oauth2.googleapis.com/token',
305	      iat: now,
306	      exp: now + 3600,
307	    }),
308	  ).toString('base64url');
309	
310	  const signer = createSign('SHA256');
311	  signer.update(`${header}.${payload}`);
312	  const sig = signer.sign({ key: sa.private_key, format: 'pem' }, 'base64url');
313	  const jwt = `${header}.${payload}.${sig}`;
314	
315	  const res = await fetch('https://oauth2.googleapis.com/token', {
316	    method: 'POST',
317	    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
318	    body: new URLSearchParams({
319	      grant_type: 'urn:ietf:params:oauth:grant-type:jwt-bearer',
320	      assertion: jwt,
321	    }),
322	    signal: AbortSignal.timeout(10_000),
323	  });
324	  if (!res.ok) {
325	    throw new Error(`Google token exchange failed: ${res.status} ${await res.text()}`);
326	  }
327	  const data = (await res.json()) as { access_token: string };
328	  return data.access_token;
329	}
330	
331	function parseServiceAccountJson(saJson: string): { client_email: string; private_key: string } {
332	  try {
333	    return JSON.parse(saJson) as { client_email: string; private_key: string };
334	  } catch {
335	    // Vercel env pulls can materialize the PEM as literal newlines inside the
336	    // JSON string. Normalize just that field, then parse normally.
337	    const normalized = saJson.replace(
338	      /"private_key"\s*:\s*"([\s\S]*?)"/,
339	      (_match, key: string) => `"private_key":"${key.replace(/\r?\n/g, '\\n')}"`,
340	    );
341	    return JSON.parse(normalized) as { client_email: string; private_key: string };
342	  }
343	}
344	
345	function stripUndefined<T extends Record<string, unknown>>(obj: T): Record<string, unknown> {
346	  return Object.fromEntries(Object.entries(obj).filter(([, value]) => value !== undefined));
347	}
348	
349	function toGeminiRestSchema(schema: unknown): unknown {
350	  if (Array.isArray(schema)) return schema.map(toGeminiRestSchema);
351	  if (!schema || typeof schema !== 'object') return schema;
352	
353	  const output: Record<string, unknown> = {};
354	  for (const [key, value] of Object.entries(schema)) {
355	    if (key === '$schema' || key === 'additionalProperties') continue;
356	    output[key] = toGeminiRestSchema(value);
357	  }
358	  return output;
359	}
