110	async function loadCapabilityMap(db: OracleDb, ids: string[]): Promise<Map<string, ModelCapability>> {
111	  if (ids.length === 0) return new Map();
112	  const unique = Array.from(new Set(ids));
113	  const rows = await db
114	    .select()
115	    .from(modelCapabilities)
116	    .where(inArray(modelCapabilities.id, unique));
117	  return new Map(
118	    rows.map((r) => [
119	      r.id,
120	      {
121	        id: r.id,
122	        provider: r.provider as ModelCapability['provider'],
123	        displayName: r.displayName,
124	        contextLength: r.contextLength,
125	        maxOutputTokens: r.maxOutputTokens,
126	        promptPer1mUsd: r.promptPer1mUsd != null ? Number(r.promptPer1mUsd) : null,
127	        completionPer1mUsd: r.completionPer1mUsd != null ? Number(r.completionPer1mUsd) : null,
128	        vision: r.vision,
129	        pdf: r.pdf,
130	        thinking: r.thinking,
131	        structuredOutputs: r.structuredOutputs,
132	        toolCalling: r.toolCalling,
133	        promptCaching: r.promptCaching,
134	        outputCap: r.outputCap,
135	        knowledgeCutoff: r.knowledgeCutoff,
136	        source: r.source as ModelCapability['source'],
137	      } satisfies ModelCapability,
138	    ]),
139	  );
