142	async function enforceCapabilitiesEnabled(db: OracleDb): Promise<boolean> {
143	  const rows = await db
144	    .select({ value: settings.value })
145	    .from(settings)
146	    .where(eq(settings.key, ENFORCE_MODEL_CAPABILITIES_SETTING_KEY))
147	    .limit(1);
