162	function resolveWithKnownCaps(
163	  modelIdOrRouteId: string,
164	  role: OracleModelRole,
165	  effort: ReasoningEffort | undefined,
166	  capMap: Map<string, ModelCapability>,
167	): OracleModelRoute | null {
168	  const directCap = capMap.get(modelIdOrRouteId);
169	  return resolveModelRoute(
170	    modelIdOrRouteId,
171	    role,
172	    effort,
173	    directCap ? capToRouteCaps(directCap) : undefined,
174	  );
175	}
