283	export async function resolvePrimaryRouteFromSettings(
284	  db: OracleDb,
285	  slot: ModelSlot,
286	): Promise<OracleModelRoute> {
287	  return (await resolveRouteCandidates(db, slot)).candidates[0]!.route;
288	}
