/**
 * Build the Gemini `thinkingConfig` for a route — but ONLY for models that
 * actually support thinking/reasoning controls. Attaching `thinkingLevel` to a
 * model that doesn't support it (e.g. gemini-2.5-flash via this adapter) makes
 * the API 400 with "Thinking level is not supported for this model", which
 * broke gemini-2.5-flash as a vision model whenever a reasoning effort was set.
 * `supportsReasoningControls` is the per-model capability flag (sourced from
 * model_capabilities.thinking), so gate on it.
 */
function geminiThinkingConfig(route: OracleModelRoute):
  | { thinkingConfig: { thinkingLevel: ThinkingLevel } }
  | Record<string, never> {
  if (!route.supportsReasoningControls) return {};
  const effort = route.reasoningEffort;
  if (!effort) return {};
  const thinkingLevel =
    effort === 'off' ? ThinkingLevel.MINIMAL
      : effort === 'low' ? ThinkingLevel.LOW
      : effort === 'medium' ? ThinkingLevel.MEDIUM
      : ThinkingLevel.HIGH;
  return { thinkingConfig: { thinkingLevel } };
}

