/**
 * Normalize a settings value so writes are idempotent and can never store a
 * double-JSON-encoded value (Bug 4). `settings.value` is a `jsonb` column, so
 * Drizzle JSON-encodes whatever JS value we pass: a bare string `"off"` is
 * stored as the JSON string `"off"` (correct, single-encoded). The pathology is
 * a writer that hands us a value that is ALREADY a JSON document as a string —
 * e.g. `'"off"'` or `'["a","b"]'` — which Drizzle then encodes a SECOND time,
 * yielding `"\"off\""` / a stringified array. Consumers (the route resolver,
 * the picker loader) expect the decoded value and silently break on the
 * double-encoded form.
 *
 * Fix: if the incoming value is a string that is itself a valid JSON document
 * decoding to a NON-string JSON value (object, array, number, boolean, null),
 * unwrap exactly one layer. We deliberately do NOT unwrap a JSON string-literal
 * like `'"off"'` here at the type level — instead we unwrap any string whose
 * trimmed form is wrapped in JSON quotes/brackets and re-parses, because the
 * only legitimate scalar string settings (model ids like `google/gemini-2.5-flash`,
 * efforts like `off`, `sync`/`batch`) are NEVER themselves valid JSON documents
 * (they have no surrounding quotes/brackets). This makes a re-write of an
 * already-corrupted value self-healing and a normal write a no-op.
 */
function normalizeSettingValue(value: unknown): unknown {
  if (typeof value !== 'string') return value;
  const trimmed = value.trim();
  const looksEncoded =
    (trimmed.startsWith('"') && trimmed.endsWith('"')) ||
    trimmed.startsWith('[') ||
    trimmed.startsWith('{');
  if (!looksEncoded) return value;
  try {
    const decoded: unknown = JSON.parse(value);
    // Recurse: handles the (pathological) triple-encode too, and stops as soon
    // as the value is no longer an encoded-string wrapper.
    return normalizeSettingValue(decoded);
  } catch {
    return value;
  }
}

