import postgres from 'postgres';
import { normalizeSettingValue, isDoubleEncodedSettingValue } from './src/routes/settings-encoding.ts';
const sql = postgres(process.env.PROD_URL, { max:1, prepare:false, connect_timeout:25 });

// 1) Scan whole table for double-encoded values (the consumer-visible bug).
const all = await sql`select key, value from settings`;
const bad = all.filter(r => isDoubleEncodedSettingValue(r.value));
console.log('Double-encoded settings BEFORE repair:', bad.map(r=>r.key).join(', ') || '(none)');

// 2) Repair each via the SAME normalizer the writer now uses, writing the
//    decoded value back through jsonb (single-encoded). Read back + assert.
for (const r of bad) {
  const fixed = normalizeSettingValue(r.value);
  // pass the decoded JS value as jsonb param -> single-encoded
  await sql`update settings set value = ${sql.json(fixed)}, updated_at = now() where key = ${r.key}`;
  const [after] = await sql`select value from settings where key = ${r.key}`;
  const ok = !isDoubleEncodedSettingValue(after.value) && JSON.stringify(after.value) === JSON.stringify(fixed);
  console.log(`  repaired ${r.key}: now ${JSON.stringify(after.value)} single-encoded=${ok}`);
}

// 3) Round-trip proof on the originally-reported key: write 'off' bare, read back.
await sql`update settings set value = ${sql.json(normalizeSettingValue('off'))} where key = 'default_extraction_reasoning_effort'`;
const [eff] = await sql`select value from settings where key='default_extraction_reasoning_effort'`;
console.log('round-trip extraction_reasoning_effort =', JSON.stringify(eff.value), 'isString+bare=', eff.value === 'off');

// 4) Re-scan to confirm zero double-encoded remain.
const all2 = await sql`select key, value from settings`;
const bad2 = all2.filter(r => isDoubleEncodedSettingValue(r.value));
console.log('Double-encoded settings AFTER repair:', bad2.map(r=>r.key).join(', ') || '(none)');
await sql.end();
EOF
